use sema_storage::Runtime;use signal_sema_storage::{DocumentKey,DocumentKind,DocumentPayload,FixtureScope,NameTableBytes,Reply,Request,SlotIdentifier};
#[tokio::test] async fn durable_single_writer_versions_and_recovers(){let dir=tempfile::tempdir().unwrap();let path=dir.path().join("isolated.sema");let key=DocumentKey{scope:FixtureScope(1),kind:DocumentKind::Logos,slot:SlotIdentifier(1)};let payload=DocumentPayload::Logos{items:vec![],names:NameTableBytes(vec![])};let runtime=Runtime::open(&path).await.unwrap();assert!(matches!(runtime.request(Request::Store{key:key.clone(),payload}).await.unwrap(),Reply::Stored(_)));runtime.shutdown().await.unwrap();let reopened=Runtime::open(&path).await.unwrap();match reopened.request(Request::Fetch{key,version:None}).await.unwrap(){Reply::Document(Some(document))=>assert_eq!(document.version.0,1),other=>panic!("{other:?}")}}
#[tokio::test] async fn fixture_allocator_is_durable(){let dir=tempfile::tempdir().unwrap();let runtime=Runtime::open(&dir.path().join("ids.sema")).await.unwrap();let reply=runtime.request(Request::AllocateIdentifiers{scope:FixtureScope(7),count:4}).await.unwrap();match reply{Reply::IdentifiersAllocated(block)=>assert_eq!((block.first,block.length),(0,4)),other=>panic!("{other:?}")}}
